#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=5e5+10,M=2e6+10,Mod=1e9+7;
inline void DN(int &x){x>=Mod?x-=Mod:0;}
inline void UP(int &x){x<0?x+=Mod:0;}
int head[N],des[M],nxt[M],cgt=1,dp[N],n,m;bool isc[M];
int tn,cdt,dfn[N],low[N],col[N],cct,sE[N],sD[N],pw[M],sz[N];
vector<int> T[N];
inline void ins(int x,int y)
{
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;
}
inline void tins(int x,int y){T[x].push_back(y);T[y].push_back(x);}
inline void tarjan(int u,int f=0)
{
	dfn[u]=low[u]=++cdt;grep(u,i)if(i!=f)
	{
		int v=des[i];if(!dfn[v])
		{
			tarjan(v,i^1);low[u]=min(low[u],low[v]);
			isc[i>>1]=(low[v]>dfn[u]);
		}
		else low[u]=min(low[u],dfn[v]);
	}
}
inline void dfs(int u)
{
	col[u]=cct;sD[cct]++;
	grep(u,i)if(!isc[i>>1]&&!col[des[i]])dfs(des[i]);
}
inline void DP(int u,int f)
{
//	printf("QwQ :: %d %d\n",u,f);
	UP(dp[u]=pw[sD[u]+sE[u]]-pw[sE[u]]);sz[u]=sE[u];
	for(int v:T[u])if(v!=f)
	{
		DP(v,u);
		dp[u]=(1ll*pw[sz[u]]*dp[v]+1ll*dp[u]*dp[v]+2ll*pw[sz[v]]*dp[u])%Mod;
		sz[u]+=sz[v]+1;
	}
}
int main()
{
	n=read();m=read();rep(1,m,i)ins(read(),read());
	pw[0]=1;rep(1,n+m,i)DN(pw[i]=pw[i-1]<<1);
	tarjan(1,0);rep(1,n,i)if(!col[i]){++cct;dfs(i);}
	rep(1,m,i)if(isc[i])tins(col[des[i<<1]],col[des[i<<1|1]]);else ++sE[col[des[i<<1]]];
	DP(1,0);int ans=dp[1];
	rep(2,cct,i){ans=(1ll*dp[i]*pw[m-sz[i]-1]+ans)%Mod;}
	printf("%d\n",ans);
//	printf("%d\n",sz[1]);
	return 0;
}
